UPDATE SURVEY
SET    SRVY_NOPE = SRVY_NOPE + 1
WHERE  SRVY_NO = #{srvyNo}

UPDATE 	EMPLOYEE
SET		EMP_MLG = EMP_MLG + #{empMlg}
WHERE 	EMP_ID = #{empId}

