INSERT INTO SURVEY (
SRVY_NO, SRVY_EMP_ID, SRVY_CN, SRVY_BGNG_DT, SRVY_END_DT,
SRVY_STTS, SRVY_NOPE, SRVY_ANON, SRVY_TTL, SRVY_MLG
