mapper.select:
SELECT D.DEPT_NM AS name, ROUND( (COUNT(CASE WHEN SE.SRVY_YN = 'Y' THEN 1 END) * 100.0) / NULLIF(COUNT(E.EMP_ID), 0), 1 ) AS value FROM DEPARTMENT D JOIN EMPLOYEE E ON D.DEPT_CD = E.DEPT_CD LEFT JOIN SURVEY_EMP SE ON E.EMP_ID = SE.EMP_ID
AND SE.SRVY_NO = #{srvyNo}
WHERE E.EMP_STTS != 'N' AND E.EMP_JBGD != '관리자' GROUP BY D.DEPT_NM, D.DEPT_CD ORDER BY D.DEPT_NM ASC

SELECT E.EMP_JBGD AS name, ROUND( (COUNT(CASE WHEN SE.SRVY_YN = 'Y' THEN 1 END) * 100.0) / NULLIF(COUNT(E.EMP_ID), 0), 1 ) AS value FROM EMPLOYEE E LEFT JOIN SURVEY_EMP SE ON E.EMP_ID = SE.EMP_ID
AND SE.SRVY_NO = #{srvyNo}
WHERE E.EMP_STTS != 'N' AND E.EMP_JBGD != '관리자' GROUP BY E.EMP_JBGD ORDER BY CASE E.EMP_JBGD WHEN '팀장' THEN 1 WHEN '대리' THEN 2 WHEN '주임' THEN 3 WHEN '사원' THEN 4 ELSE 5 END ASC
